const V09_ARCHIVE_CARDS=[{"id":"CITY_ARC_001","type":"CITY","title":"Альба-Лонга","original":"Alba Longa","subtitle":"легендарная прародина Ромула и Рема","era":"Ранний Рим","region":"Альбанские холмы","date":"легендарная эпоха до основания Рима","rarity":"RARE","difficulty":2,"summary":"Альба-Лонга — легендарный латинский город, который римская традиция считала родиной династии Ромула и Рема.","importance":"Карточка связывает основание Рима с более древним миром латинских поселений и династических легенд.","facts":["Точное местоположение Альба-Лонги остаётся предметом споров.","Рея Сильвия и Нумитор в легенде связаны с Альба-Лонгой.","Римская традиция выводила через город происхождение ранних царей."],"tags":["Альба-Лонга","Лаций","миф"],"stats":{"influence":5,"complexity":4,"legacy":6,"military":2,"culture":7,"politics":4,"religion":4,"economy":2,"connections":7},"loc":{"label":"Альбанские холмы","x":60,"y":55},"image":{"file":"Castel Gandolfo and Lake Albano.jpg","caption":"Окрестности Альбанских холмов и озера Альбано","credit":"Wikimedia Commons","license":"см. страницу файла","focus":"50% 50%"}},{"id":"REG_ARC_001","type":"CITY","title":"Тибр","original":"Tiber","subtitle":"река, на которой вырос Рим","era":"Античность","region":"Центральная Италия","date":"древность","rarity":"RARE","difficulty":2,"summary":"Тибр связывал ранний Рим с морем, соседними поселениями, торговлей и удобными переправами.","importance":"География реки объясняет, почему город возник именно на этом участке Лация.","facts":["Рим возник у удобной переправы через Тибр.","Остров Тиберина облегчал переход через реку.","Через Тибр Рим получал связь с побережьем и Остием."],"tags":["Тибр","география","торговля"],"stats":{"influence":7,"complexity":2,"legacy":8,"military":4,"culture":5,"politics":4,"religion":3,"economy":8,"connections":8},"loc":{"label":"Рим","x":56,"y":50},"image":{"file":"Tiber River Rome.jpg","caption":"Река Тибр в Риме","credit":"Wikimedia Commons","license":"см. страницу файла","focus":"50% 50%"}},{"id":"REL_ARC_001","type":"RELIGION","title":"Авгурия","original":"Augury","subtitle":"чтение воли богов по знамениям","era":"Ранний Рим","region":"Италия","date":"античность","rarity":"RARE","difficulty":3,"summary":"Авгуры толковали знамения, прежде всего поведение птиц, и помогали определить, одобряют ли боги важное решение.","importance":"Римская политика и религия не были разделены: общественные действия требовали правильных ритуалов и знаков.","facts":["Авгур не предсказывал будущее в бытовом смысле, а толковал божественное одобрение.","Наблюдение за птицами было одним из известных видов ауспиций.","Легенда о Ромуле и Реме тоже включает спор о знамениях."],"tags":["религия","авгуры","знамения"],"stats":{"influence":6,"complexity":5,"legacy":6,"military":2,"culture":8,"politics":7,"religion":10,"economy":1,"connections":7},"loc":{"label":"Рим","x":56,"y":50},"image":{"file":"Augur, Nordisk familjebok.png","caption":"Изображение римского авгура","credit":"Wikimedia Commons","license":"Public Domain / см. страницу файла","focus":"50% 40%"}},{"id":"PER_ARC_001","type":"PERSON","title":"Тит Татий","original":"Titus Tatius","subtitle":"сабинский царь и соправитель Ромула","era":"Легендарный ранний Рим","region":"Лаций и Сабина","date":"легендарная эпоха","rarity":"RARE","difficulty":3,"summary":"Тит Татий — сабинский царь, который в римской традиции после конфликта стал соправителем Ромула.","importance":"Его история показывает, как римляне объясняли включение сабинян в новое политическое сообщество.","facts":["Тит Татий относится к легендарному слою ранней истории.","После примирения сабинян и римлян он якобы правил вместе с Ромулом.","Сюжет подчёркивает смешанное происхождение раннего населения Рима."],"tags":["сабиняне","Ромул","царь"],"stats":{"influence":4,"complexity":4,"legacy":5,"military":5,"culture":6,"politics":7,"religion":3,"economy":1,"connections":6},"loc":{"label":"Сабина","x":60,"y":45},"image":{"file":"Titus Tatius.jpg","caption":"Тит Татий в поздней художественной традиции","credit":"Wikimedia Commons","license":"см. страницу файла","focus":"50% 35%"}},{"id":"PER_ARC_002","type":"PERSON","title":"Тарпея","original":"Tarpeia","subtitle":"девушка из легенды о сабинской войне","era":"Легендарный ранний Рим","region":"Рим","date":"легендарная эпоха","rarity":"EPIC","difficulty":4,"summary":"Тарпея — персонаж римской легенды, связанный с предательством крепости и гибелью под щитами сабинян.","importance":"Её история стала римским рассказом о цене предательства, двусмысленности мотива и политической памяти.","facts":["Источники по-разному объясняли мотив Тарпеи.","По известной версии она потребовала то, что сабиняне носили на левой руке.","С Тарпеей связывали Тарпейскую скалу на Капитолии."],"tags":["сабиняне","предательство","легенда"],"stats":{"influence":5,"complexity":7,"legacy":7,"military":2,"culture":9,"politics":5,"religion":2,"economy":2,"connections":7},"loc":{"label":"Капитолий","x":56,"y":50},"image":{"file":"Tarpeia.jpg","caption":"Тарпея в художественной традиции","credit":"Wikimedia Commons","license":"см. страницу файла","focus":"50% 35%"}},{"id":"LOC_ARC_001","type":"CITY","title":"Квиринал","original":"Quirinal Hill","subtitle":"один из ключевых холмов раннего Рима","era":"Ранний Рим","region":"Рим","date":"античность","rarity":"RARE","difficulty":2,"summary":"Квиринал — один из римских холмов, который традиция связывала с сабинским населением и расширением раннего города.","importance":"Он помогает увидеть Рим не как город, возникший мгновенно, а как объединение нескольких поселений и общин.","facts":["Квиринал находится северо-восточнее древнего центра Рима.","Название связывали с богом Квирином.","В традиции холм имел сильные сабинские ассоциации."],"tags":["Рим","холмы","сабиняне"],"stats":{"influence":4,"complexity":3,"legacy":6,"military":2,"culture":6,"politics":4,"religion":6,"economy":2,"connections":6},"loc":{"label":"Рим","x":56,"y":50},"image":{"file":"Quirinal Hill Rome.jpg","caption":"Квиринальский холм в Риме","credit":"Wikimedia Commons","license":"см. страницу файла","focus":"50% 50%"}},{"id":"REL_ARC_002","type":"RELIGION","title":"Храм Януса","original":"Temple of Janus","subtitle":"ворота войны и мира","era":"Римское царство и Республика","region":"Рим","date":"античность","rarity":"EPIC","difficulty":4,"summary":"Храм Януса в римской традиции имел двери, которые открывали во время войны и закрывали в период мира.","importance":"Этот образ соединяет религию, государственную идеологию и редкость настоящего мира в истории Рима.","facts":["Традиция связывала установление обычая с Нумой Помпилием.","Закрытые двери символизировали отсутствие войны.","Поздние правители использовали закрытие дверей как политический символ."],"tags":["Янус","война","мир"],"stats":{"influence":6,"complexity":4,"legacy":8,"military":6,"culture":8,"politics":8,"religion":10,"economy":1,"connections":8},"loc":{"label":"Римский форум","x":56,"y":50},"image":{"file":"Temple of Janus coin.jpg","caption":"Изображение храма Януса на римской монете","credit":"Wikimedia Commons","license":"см. страницу файла","focus":"50% 50%"}},{"id":"PER_ARC_003","type":"PERSON","title":"Анк Марций","original":"Ancus Marcius","subtitle":"четвёртый царь римской традиции","era":"Римское царство","region":"Рим и Лаций","date":"традиционно VII век до н. э.","rarity":"EPIC","difficulty":4,"summary":"Анк Марций — четвёртый царь в традиционном списке, которому приписывали войны, мост через Тибр и развитие Остии.","importance":"Его образ показывает переход от сакрального царя к правителю, который расширяет инфраструктуру и контроль территории.","facts":["Анка Марция считали внуком Нумы Помпилия.","Ему традиционно приписывали первый деревянный мост через Тибр.","С его именем связывали основание Остии, хотя точность традиции спорна."],"tags":["цари","Тибр","Остия"],"stats":{"influence":6,"complexity":5,"legacy":7,"military":6,"culture":5,"politics":7,"religion":5,"economy":8,"connections":8},"loc":{"label":"Рим","x":56,"y":50},"image":{"file":"Ancus Marcius.jpg","caption":"Анк Марций в поздней иконографической традиции","credit":"Wikimedia Commons","license":"см. страницу файла","focus":"50% 30%"}},{"id":"PER_ARC_004","type":"PERSON","title":"Сервий Туллий","original":"Servius Tullius","subtitle":"царь реформ и городского порядка","era":"Позднее Римское царство","region":"Рим","date":"традиционно VI век до н. э.","rarity":"LEGENDARY","difficulty":6,"summary":"Сервий Туллий — шестой царь римской традиции, которому приписывали перепись, военную организацию и перестройку гражданского порядка.","importance":"Его образ стал объяснением того, как Рим связал имущество, военную службу и политические права.","facts":["Источники приписывали ему цензовое деление населения.","С его именем традиционно связывали Сервиеву стену.","Легенда о его происхождении содержит необычные мотивы рабского рождения и божественного знака."],"tags":["реформы","цари","перепись"],"stats":{"influence":8,"complexity":8,"legacy":9,"military":7,"culture":6,"politics":10,"religion":5,"economy":8,"connections":9},"loc":{"label":"Рим","x":56,"y":50},"image":{"file":"Servius Tullius.jpg","caption":"Сервий Туллий в художественной традиции","credit":"Wikimedia Commons","license":"см. страницу файла","focus":"50% 30%"}},{"id":"ART_ARC_001","type":"ARTIFACT","title":"Клоака Максима","original":"Cloaca Maxima","subtitle":"дренажная система раннего Рима","era":"Царский и республиканский Рим","region":"Рим","date":"формировалась в ранний период Рима","rarity":"EPIC","difficulty":4,"summary":"Клоака Максима — древняя система отвода воды, которая помогла осушить низины между холмами и сформировать городской центр.","importance":"Она показывает, что история Рима — это не только войны и цари, но и тяжёлая инженерная работа по созданию города.","facts":["Система развивалась постепенно и не была построена в один момент.","Осушение низины помогло развитию района Форума.","Части древнего сооружения продолжают существовать."],"tags":["инфраструктура","Форум","город"],"stats":{"influence":7,"complexity":5,"legacy":9,"military":1,"culture":7,"politics":4,"religion":2,"economy":9,"connections":8},"loc":{"label":"Римский форум","x":56,"y":50},"image":{"file":"Cloaca Maxima Rome.jpg","caption":"Выход Клоаки Максимы у Тибра","credit":"Wikimedia Commons","license":"см. страницу файла","focus":"50% 50%"}},{"id":"ART_ARC_002","type":"ARTIFACT","title":"Сервиева стена","original":"Servian Wall","subtitle":"укрепления республиканского Рима","era":"Ранний Рим и Республика","region":"Рим","date":"основные сохранившиеся участки относятся к IV веку до н. э.","rarity":"EPIC","difficulty":5,"summary":"Сервиева стена — оборонительный контур Рима, традиционно связанный с Сервием Туллием, хотя сохранившиеся участки позднее.","importance":"Карточка учит отделять традиционное имя сооружения от археологической датировки его основных остатков.","facts":["Название стены связывает её с царём Сервием Туллием.","Большая часть известных остатков относится к IV веку до н. э.","Стена окружала значительно расширившийся городской центр."],"tags":["стены","археология","Рим"],"stats":{"influence":6,"complexity":7,"legacy":8,"military":9,"culture":5,"politics":5,"religion":1,"economy":6,"connections":7},"loc":{"label":"Рим","x":56,"y":50},"image":{"file":"Servian Wall Rome.jpg","caption":"Сохранившийся участок Сервиевой стены","credit":"Wikimedia Commons","license":"см. страницу файла","focus":"50% 50%"}},{"id":"PER_ARC_005","type":"PERSON","title":"Лукреция","original":"Lucretia","subtitle":"женщина в легенде о падении царской власти","era":"Конец Римского царства","region":"Рим и Коллация","date":"традиционно конец VI века до н. э.","rarity":"LEGENDARY","difficulty":7,"summary":"Лукреция — центральная фигура римского рассказа о насилии, чести и восстании против Тарквиниев.","importance":"Её история стала политическим мифом происхождения Республики и веками влияла на искусство и представления о тирании.","facts":["Рассказ известен по более поздним литературным источникам.","Событие связывали с Секстом Тарквинием, сыном последнего царя.","После её смерти сторонники Брута подняли восстание против монархии."],"tags":["Лукреция","Республика","тирания"],"stats":{"influence":9,"complexity":9,"legacy":10,"military":1,"culture":10,"politics":10,"religion":2,"economy":1,"connections":10},"loc":{"label":"Коллация","x":60,"y":50},"image":{"file":"The Death of Lucretia.jpg","caption":"Смерть Лукреции в европейской живописи","credit":"Wikimedia Commons","license":"Public Domain / см. страницу файла","focus":"50% 40%"}},{"id":"PER_ARC_006","type":"PERSON","title":"Луций Юний Брут","original":"Lucius Junius Brutus","subtitle":"легендарный основатель Республики","era":"Ранняя Республика","region":"Рим","date":"традиционно VI век до н. э.","rarity":"LEGENDARY","difficulty":6,"summary":"Луций Юний Брут — герой римской традиции, который возглавил изгнание Тарквиниев и стал одним из первых консулов.","importance":"Через Брута римляне формулировали идеал непримиримости к царской власти и личной жертвы ради Республики.","facts":["Его биография сильно насыщена легендарными мотивами.","Брут связан с восстанием после гибели Лукреции.","Традиция приписывала ему казнь собственных сыновей за участие в заговоре."],"tags":["Брут","Республика","консулы"],"stats":{"influence":9,"complexity":7,"legacy":10,"military":6,"culture":8,"politics":10,"religion":3,"economy":2,"connections":10},"loc":{"label":"Рим","x":56,"y":50},"image":{"file":"Lucius Junius Brutus Capitoline Museums.jpg","caption":"Бюст, традиционно называемый Луцием Юнием Брутом","credit":"Wikimedia Commons","license":"см. страницу файла","focus":"50% 32%"}},{"id":"ORG_ARC_001","type":"FACTION","title":"Римские консулы","original":"Roman consuls","subtitle":"двойная высшая магистратура Республики","era":"Римская республика","region":"Рим","date":"с начала Республики","rarity":"EPIC","difficulty":5,"summary":"Консулы были двумя ежегодно избираемыми высшими магистратами, которые делили власть и командовали армиями.","importance":"Коллегиальность и ограниченный срок полномочий должны были не допустить возвращения единоличного царя.","facts":["Обычно избирали двух консулов на один год.","Каждый мог ограничивать действия коллеги.","Консулы обладали империем — правом высшего командования и власти."],"tags":["консулы","Республика","магистратуры"],"stats":{"influence":9,"complexity":6,"legacy":9,"military":8,"culture":5,"politics":10,"religion":4,"economy":5,"connections":9},"loc":{"label":"Рим","x":56,"y":50},"image":{"file":"Roman consul.jpg","caption":"Образ римского консула","credit":"Wikimedia Commons","license":"см. страницу файла","focus":"50% 35%"}},{"id":"ART_ARC_003","type":"ARTIFACT","title":"Фасции","original":"Fasces","subtitle":"знак власти римских магистратов","era":"Римская республика и Империя","region":"Рим","date":"античность","rarity":"RARE","difficulty":3,"summary":"Фасции — связка прутьев, которую ликторы несли перед магистратом как знак его власти наказывать и командовать.","importance":"Этот предмет визуально объясняет римское понятие государственной власти и её публичное представление.","facts":["Фасции несли ликторы.","Вне Рима в связку мог включаться топор как знак права казни.","Позднее символ получил множество новых политических значений."],"tags":["власть","ликторы","символ"],"stats":{"influence":7,"complexity":4,"legacy":10,"military":5,"culture":9,"politics":9,"religion":2,"economy":1,"connections":8},"loc":{"label":"Рим","x":56,"y":50},"image":{"file":"Fasces lictoriae.svg","caption":"Схематическое изображение римских фасций","credit":"Wikimedia Commons","license":"см. страницу файла","focus":"50% 50%"}}];
